parameters.jsCode:
const text = $input.first().json.text ?? '';

const lines = text
  .split(/\r?\n/)
  .map(l => l.trim())
  .filter(l => l.length > 0);

// ── helpers ───────────────────────────────────────────────────────────────────
const KNOWN_UNITS = /^(Set|Each|Sq\.?\s*Ft\.?|Gallon|Gallons|Linear\s*Ft|LF|SF|SY|Pair|Roll|Box|Bag|Sheet)$/i;
const IS_DECIMAL  = /^\d+\.?\d*$/;
const IS_PRICE    = /^\$[\d,]+(?:\.\d{1,2})?$/;
const IS_DATE     = /^(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\s+\d{1,2},?\s+\d{4}$/i;
const IS_PAGE     = /^Page\s+\d+\s+of\s+\d+$/i;
const IS_EMAIL    = /[\w.+\-]+@[\w.\-]+\.[a-z]{2,}/i;
const MS_END      = /^(?:TERMS|Agreed|PLEASE\s+FEEL|Page\s+\d)/i;

const toNum = s => parseFloat(s.replace(/[$,]/g, ''));

// ── client info ───────────────────────────────────────────────────────────────
const dateIdx = lines.findIndex(l => IS_DATE.test(l));
if (dateIdx < 0) throw new Error('Could not find date line — PDF structure unrecognized.');

const clientName    = lines[dateIdx + 1] ?? null;
const clientAddress = lines[dateIdx + 2] ?? null;
const clientPhone   = lines[dateIdx + 3] ?? null;
const clientEmail   = (lines[dateIdx + 4] ?? '').match(IS_EMAIL)?.[0] ?? null;

// ── project type ──────────────────────────────────────────────────────────────
const emailLineIdx = dateIdx + 4;

let projectType = null;
{
  const headerLine = lines[emailLineIdx + 1] ?? '';
  const parts      = headerLine.split(' - ');
  if (parts.length >= 3) {
    let pt = parts[parts.length - 1].trim();
    if (!pt.includes(' ')) {
      const nextLine = lines[emailLineIdx + 2] ?? '';
      if (!nextLine.includes(' - ')) pt = (pt + ' ' + nextLine).trim();
    }
    projectType = pt || null;
  }
}

// ── milestones ────────────────────────────────────────────────────────────────
const normalize = s => String(s ?? '').replace(/\s+/g, ' ').trim();

const msHeaderIdx = lines.findIndex(l => {
  const x = normalize(l);
  return /^Payment Milestones?$/i.test(x) || /^Milestones?$/i.test(x) || /^Milestone$/i.test(x);
});

const msAmountIdx = lines.findIndex((l, i) => {
  if (i <= msHeaderIdx) return false;
  const x = normalize(l);
  return /^Amount$/i.test(x) || /\bAmount\b/i.test(x);
});

if (msHeaderIdx < 0 || msAmountIdx < 0) {
  throw new Error(
    'Could not find Payment Milestones table. Nearby lines: ' +
    lines
      .map((line, i) => `${i}: ${line}`)
      .filter(row => /milestone|payment|amount|total/i.test(row))
      .slice(0, 30)
      .join(' | ')
  );
}

const msEndIdx = lines.findIndex((l, i) => i > msAmountIdx && MS_END.test(l));
const afterAmt = lines.slice(msAmountIdx + 1, msEndIdx >= 0 ? msEndIdx : undefined);

const msNamesLeft = lines.slice(msHeaderIdx + 1, msAmountIdx)
  .filter(l => {
    const x = normalize(l);
    return !/^Payment Milestones?$/i.test(x)
      && !/^Milestones?$/i.test(x)
      && !/^Milestone$/i.test(x)
      && !/^Amount$/i.test(x)
      && !/^Total$/i.test(x)
      && !/^Note:/i.test(x)
      && !IS_PAGE.test(x);
  });

const msNamesRight = afterAmt
  .filter(l => {
    const x = normalize(l);
    return !IS_PRICE.test(x)
      && !IS_PAGE.test(x)
      && !IS_DECIMAL.test(x)
      && !/^Total$/i.test(x)
      && !/^Note:/i.test(x);
  });

const rawMilestoneRows = [...msNamesLeft, ...msNamesRight];

const milestones = rawMilestoneRows
  .map(row => {
    const line = normalize(row);
    const priceMatch = line.match(/\$[\d,]+(?:\.\d{1,2})?/);

    if (!priceMatch) {
      return {
        name: line,
        amount: 0,
      };
    }

    return {
      name: line.replace(priceMatch[0], '').trim(),
      amount: toNum(priceMatch[0]),
    };
  })
  .filter(m => m.name && !/^Amount$/i.test(m.name));

if (milestones.length === 0) throw new Error('Milestones table parsed 0 rows.');

// ── finish materials ──────────────────────────────────────────────────────────
const materials = [];
let suppliedBy = '';

const fmStartIdx = lines.findIndex(l => {
  const x = normalize(l);
  return /finish material|material estimation|materials/i.test(x)
    && !/payment|milestone/i.test(x);
});

const fmEndIdx = lines.findIndex((l, i) => {
  if (i <= fmStartIdx) return false;
  return /payment milestones?|milestones?/i.test(normalize(l));
});

if (fmStartIdx >= 0) {
  const rawFmLines = lines
    .slice(fmStartIdx + 1, fmEndIdx >= 0 ? fmEndIdx : undefined)
    .map(normalize)
    .filter(Boolean);

  const suppliedByLine = rawFmLines.find(l =>
    /^PROVIDE BY CLIENT$/i.test(l) || /^PROVIDED BY CLIENT$/i.test(l)
  );

  if (suppliedByLine) {
    suppliedBy = 'By Client';
  }

const projectTypeLower = normalize(projectType).toLowerCase();

const fmLines = rawFmLines
  .filter(l =>
    l
    && normalize(l).toLowerCase() !== projectTypeLower
    && !/^Material$/i.test(l)
    && !/^Measure$/i.test(l)
    && !/^(Qty|Quantity)$/i.test(l)
    && !/^Unit Price$/i.test(l)
    && !/^Approx\.?\s*Cost$/i.test(l)
    && !/^Approx\s*Total/i.test(l)
    && !/^PROVIDE BY CLIENT$/i.test(l)
    && !/^PROVIDED BY CLIENT$/i.test(l)
    && !/^Page\s+\d+\s+of\s+\d+$/i.test(l)
    && !/^Finish Materials?/i.test(l)
    && !/^Material\s+Measure\s+(Qty|Quantity)\s+Unit Price\s+Approx/i.test(l)
  );

  const unitPattern = '(Set|Each|Sq\\.?\\s*Ft\\.?|Gallon|Gallons|Linear\\s*Ft|LF|SF|SY|Pair|Roll|Box|Bag|Sheet)';
  const rowPattern = new RegExp(
    `^(.+?)\\s+${unitPattern}\\s+(\\d+(?:\\.\\d+)?)\\s+(\\$[\\d,]+(?:\\.\\d{1,2})?)\\s+(\\$[\\d,]+(?:\\.\\d{1,2})?)$`,
    'i'
  );

  let pending = '';

  for (const line of fmLines) {
    const candidate = pending ? `${pending} ${line}` : line;
    const match = candidate.match(rowPattern);

    if (match) {
      materials.push({
        material:    match[1].trim(),
        measure:     match[2].trim(),
        supplied_by: suppliedBy || 'By Client',
        qty:         Number(match[3]),
        unit_price:  toNum(match[4]),
        approx_cost: toNum(match[5]),
      });
      pending = '';
    } else {
      pending = candidate;
    }
  }
}

// ── validation ────────────────────────────────────────────────────────────────
if (!clientName)             throw new Error('client_name not found.');
if (!clientEmail)            throw new Error('client_email not found.');
if (!projectType)            throw new Error('project_type not found.');
if (milestones.length === 0) throw new Error('No milestones parsed.');

// ── output ────────────────────────────────────────────────────────────────────
return [{
  json: {
    slack_event_id:   $json.slack_event_id ?? '',
    slack_channel_id: $json.slack_channel_id ?? '',
    slack_file_id:    $json.slack_file_id ?? '',
    slack_file_url:   $json.slack_file_url ?? '',
    slack_file_name:  $json.slack_file_name ?? '',
    received_at:      $now.toISO(),

    client_name:      clientName,
    client_email:     clientEmail,
    client_phone:     clientPhone,
    client_address:   clientAddress,
    project_type:     projectType,
    milestones,
    finish_materials: materials,
  },
}];

